#!/usr/bin/env bash
set -e
HOME_DIR="$HOME/promptdeed"

echo ""
echo "Installing Promptdeed terminal AI agent to $HOME_DIR..."
mkdir -p "$HOME_DIR/memory" "$HOME_DIR/sessions" "$HOME_DIR/bin"

base64 -d > "$HOME_DIR/bin/promptdeed" <<'PYBLOB'

PYBLOB
chmod +x "$HOME_DIR/bin/promptdeed"

mkdir -p "$HOME/.local/bin"
ln -sf "$HOME_DIR/bin/promptdeed" "$HOME/.local/bin/promptdeed"

if ! echo "$PATH" | grep -q "$HOME/.local/bin"; then
  for rc in "$HOME/.bashrc" "$HOME/.zshrc"; do
    [ -f "$rc" ] && (grep -q "$HOME/.local/bin" "$rc" || echo '''export PATH="$HOME/.local/bin:$PATH"''' >> "$rc")
  done
  export PATH="$HOME/.local/bin:$PATH"
fi

# Detect Google Drive on ChromeOS
DRIVE=""
for p in /mnt/chromeos/GoogleDrive/MyDrive "$HOME/GoogleDrive" "$HOME/Google Drive"; do
  if [ -d "$p" ]; then DRIVE="$p"; break; fi
done

if [ -n "$DRIVE" ]; then
  mkdir -p "$DRIVE/Promptdeed/memory" "$DRIVE/Promptdeed/sessions"
  echo ""
  echo "  Google Drive detected: $DRIVE"
  echo "  All AI conversations + memory will save to: $DRIVE/Promptdeed/"
else
  echo ""
  echo "  Google Drive not detected. Saving locally to $HOME_DIR/"
  echo "  To sync to Drive: ChromeOS Files app → right-click Google Drive → Share with Linux"
  echo "  Then re-run this installer."
fi

if command -v ollama >/dev/null 2>&1; then
  echo ""
  echo "Pulling llama3.1 model (one-time, ~4.7GB)..."
  ollama pull llama3.1 || echo "[skip — pull manually later: ollama pull llama3.1]"
fi

echo ""
echo "================================================"
echo "  Installed. Launching agent now."
echo "  Run again anytime with:  promptdeed"
echo "================================================"
echo ""
exec "$HOME_DIR/bin/promptdeed" < /dev/tty
